// ── MAIN ──────────────────────────────────────────────────────────────────────
export default function App() {
  const [cards, setCards] = useState([]);
  const [screen, setScreen] = useState("catch"); // catch | ideas | performance | edit
  const [editing, setEditing] = useState(null);
  const [prevScreen, setPrevScreen] = useState("ideas");

  useEffect(()=>{
    try {
      const r=localStorage.getItem(STORAGE_KEY);
      if(!r) {
        // migrate from old key
        const old=localStorage.getItem("lemon-catch-v2");
        if(old){const p=JSON.parse(old);if(Array.isArray(p))setCards(p);}
      } else {
        const p=JSON.parse(r);if(Array.isArray(p))setCards(p);
      }
    } catch(_){}
  },[]);

  const saveCards = u => { setCards(u); persist(u); };
  const addCard = form => saveCards([form,...cards]);
  const updateCard = form => saveCards(cards.map(c=>c.id===form.id?form:c));
  const deleteCard = id => { saveCards(cards.filter(c=>c.id!==id)); setScreen(prevScreen); };
  const moveStage = (id,stage) => saveCards(cards.map(c=>c.id===id?{...c,stage}:c));

  const openEdit = (card, from) => { setPrevScreen(from); setEditing(card); setScreen("edit"); };

  const navBg = "rgba(255,253,247,0.97)";
  const navItems = [
    {key:"catch", icon:"🎣", label:"Catch"},
    {key:"ideas", icon:"📚", label:"My Ideas"},
    {key:"performance", icon:"📊", label:"Performance"},
    {key:"contact", icon:"✉️", label:"About"},
  ];

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Syne:wght@700;800&family=Caveat:wght@500;700&family=DM+Sans:wght@400;500;600;700&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;}
        body{background:#f5f0dc;}
        ::-webkit-scrollbar{width:4px;}
        ::-webkit-scrollbar-thumb{background:#d4c060;border-radius:3px;}
        textarea:focus,input:focus,select:focus{border-color:#c8900a!important;outline:none;}
      `}</style>

      <div style={{position:"fixed",inset:0,zIndex:0,
        backgroundImage:`url('data:image/jpeg;base64,${LEMON_BG}')`,
        backgroundRepeat:"repeat",backgroundSize:"320px auto",opacity:0.08}}/>
      <div style={{position:"fixed",inset:0,zIndex:1,background:"rgba(255,253,247,0.85)"}}/>

      <div style={{position:"relative",zIndex:2,minHeight:"100vh",paddingBottom:80}}>
        {screen==="catch" && <CatchScreen onSave={addCard} onViewIdeas={()=>setScreen("ideas")}/>}
        {screen==="ideas" && <IdeasScreen cards={cards} onEdit={c=>openEdit(c,"ideas")} onMove={moveStage} onCatch={()=>setScreen("catch")}/>}
        {screen==="performance" && <PerformanceScreen cards={cards} onEdit={c=>openEdit(c,"performance")} onMove={moveStage}/>}
        {screen==="contact" && <ContactScreen/>}
        {screen==="edit" && <EditScreen card={editing} onBack={()=>setScreen(prevScreen)}
          onSave={form=>{updateCard(form);setScreen(prevScreen);}} onDelete={deleteCard}/>}
      </div>

      {/* Bottom nav — hidden on edit screen */}
      {screen!=="edit" && (
        <div style={{position:"fixed",bottom:0,left:0,right:0,zIndex:50,
          background:navBg, borderTop:"2px solid rgba(200,180,60,0.35)",
          display:"flex", justifyContent:"center", backdropFilter:"blur(10px)"}}>
          {navItems.map(tab=>(
            <button key={tab.key} onClick={()=>setScreen(tab.key)}
              style={{flex:1, maxWidth:160, background:"none", border:"none",
                padding:"12px 8px 10px", cursor:"pointer",
                borderTop:screen===tab.key?"3px solid #c8900a":"3px solid transparent",
                display:"flex", flexDirection:"column", alignItems:"center", gap:3}}>
              <span style={{fontSize:24}}>{tab.icon}</span>
              <span style={{fontFamily:"'DM Sans',sans-serif", fontSize:11,
                color:screen===tab.key?"#F5C800":"#A09060",
                fontWeight:screen===tab.key?700:400}}>
                {tab.label}
              </span>
            </button>
          ))}
        </div>
      )}
    </>
  );
}
